PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE IF NOT EXISTS "d1_migrations"(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE reports (
  id TEXT PRIMARY KEY NOT NULL,
  building_name TEXT NOT NULL CHECK(length(building_name) BETWEEN 2 AND 120),
  address TEXT NOT NULL CHECK(length(address) BETWEEN 5 AND 240),
  state TEXT NOT NULL,
  latitude REAL NOT NULL CHECK(latitude BETWEEN -90 AND 90),
  longitude REAL NOT NULL CHECK(longitude BETWEEN -180 AND 180),
  damage_type TEXT NOT NULL CHECK(damage_type IN ('cracks', 'moderate', 'severe', 'collapse')),
  description TEXT NOT NULL CHECK(length(description) BETWEEN 10 AND 2000),
  contact_name TEXT,
  contact_phone TEXT,
  contact_email TEXT,
  contact_consent INTEGER NOT NULL DEFAULT 0 CHECK(contact_consent IN (0, 1)),
  status TEXT NOT NULL DEFAULT 'published' CHECK(status IN ('published', 'hidden')),
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL
, needs_help INTEGER NOT NULL DEFAULT 0 CHECK(needs_help IN (0, 1)), city TEXT NOT NULL DEFAULT '' CHECK(length(city) <= 120), source_name TEXT, source_id TEXT, source_url TEXT, source_updated_at TEXT);
CREATE TABLE report_images (
  id TEXT PRIMARY KEY NOT NULL,
  report_id TEXT NOT NULL,
  r2_key TEXT NOT NULL UNIQUE,
  mime_type TEXT NOT NULL CHECK(mime_type = 'image/webp'),
  size_bytes INTEGER NOT NULL CHECK(size_bytes > 0 AND size_bytes <= 2097152),
  width INTEGER NOT NULL CHECK(width > 0 AND width <= 1920),
  height INTEGER NOT NULL CHECK(height > 0 AND height <= 1920),
  position INTEGER NOT NULL CHECK(position BETWEEN 0 AND 4),
  created_at TEXT NOT NULL,
  FOREIGN KEY (report_id) REFERENCES reports(id) ON DELETE CASCADE,
  UNIQUE(report_id, position)
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_reports_created_at ON reports(created_at DESC);
CREATE INDEX idx_reports_state ON reports(state);
CREATE INDEX idx_reports_damage_type ON reports(damage_type);
CREATE INDEX idx_reports_status ON reports(status);
CREATE INDEX idx_reports_coordinates ON reports(latitude, longitude);
CREATE INDEX idx_report_images_report_id ON report_images(report_id, position);
CREATE INDEX idx_reports_needs_help ON reports(needs_help);
CREATE INDEX idx_reports_city ON reports(city);
CREATE UNIQUE INDEX idx_reports_source_unique
ON reports(source_name, source_id)
WHERE source_name IS NOT NULL AND source_id IS NOT NULL;
CREATE INDEX idx_reports_map_view
ON reports(status, latitude, longitude);
CREATE INDEX idx_reports_published_created_at
ON reports(created_at DESC)
WHERE status = 'published';
CREATE INDEX idx_reports_published_state_created_at
ON reports(state, created_at DESC)
WHERE status = 'published';
CREATE INDEX idx_reports_published_damage_created_at
ON reports(damage_type, created_at DESC)
WHERE status = 'published';
CREATE INDEX idx_reports_published_viewport_created_at
ON reports(latitude, longitude, created_at DESC)
WHERE status = 'published';
CREATE INDEX idx_reports_published_needs_help
ON reports(needs_help, updated_at)
WHERE status = 'published';
