INSERT INTO "reports" ("id","building_name","address","state","latitude","longitude","damage_type","description","contact_name","contact_phone","contact_email","contact_consent","status","created_at","updated_at","needs_help","city","source_name","source_id","source_url","source_updated_at") VALUES('90da5bca-12ad-44b1-9994-c12da792a73a','Edificio Las Palmas o punta piedra (ver video)','Avenida José María España, Macuto 1164, La Guaira, Venezuela','La Guaira',10.6095842,-66.8757252,'collapse',replace('Edificio desplomado\n— 25/06/2026 —\nSe observa en el video, el colapso de edificios mencionados: las palmas, punta brisas, no se aclara si punta piedras también\n— Paredes caídas, paredes de pasillos caídas, fachada en muy mal estado, parecen que las columnas aguantaron\n— Los vecinos pudieron evacuar el edificio. Solo quedó una persona que insiste en permanecer dentro. Se observan daños en el exterior, como muros agrietados. Además, los vecinos indicaron que las tuberías están rotas y que las escaleras están bloqueadas.\n— Las personas pudieron salir del edificio, solo quedo una persona que quiere mantenerse en el lugar, se observan daños en la estructura, pero no tenemos con precision si hay daños en columnas o vigas, las tuberias se rompieron y las escaleras estan tapeadas\n— Colapsado\n— Al menos 4 personas atrapadas','\n',char(10)),NULL,NULL,NULL,0,'published','2026-06-26T19:00:01.117Z','2026-06-26T19:00:01.117Z',0,'Macuto','terremotovenezuela.com','682db6d9-eefd-4d5c-b408-8e138778a4f0','https://terremotovenezuela.com/edificio/682db6d9-eefd-4d5c-b408-8e138778a4f0','2026-06-26T18:05:49.023+00:00');
