INSERT INTO "reports" ("id","building_name","address","state","latitude","longitude","damage_type","description","contact_name","contact_phone","contact_email","contact_consent","status","created_at","updated_at","needs_help","city","source_name","source_id","source_url","source_updated_at") VALUES('e7da3ae6-1829-4f69-bd54-be915c011d02','Residencias El Molino','Avenida Guaicaipuro, Caraballeda 1165, La Guaira, Venezuela','La Guaira',10.6122196,-66.8437053,'collapse',replace('Edificio completamente colapsado.\n— 25/06/2026 —\nSe requiere maquinaria y rescatistas\n— Edificio completamente destruido.\n— Se cree hay gente atrapada, piso 1 y 2 colapsaron al sotano y no hay actividad de rescate aun .\n— Le faltan 3 pisos. el edificio tenia aproximadamente 7 pisos, piso 1 y 2 y 3 estan destruidos y seguramente hay gente atrapada.  Conocemos gente que vive en el primer piso que no aparecen y testimonios de sobrevivientes del edificio dicen que no saben nada de los vecinos de los primeros pisos aun\n— Primeros pisos colapsados, gente no logro salir. Se encuentran atrapados','\n',char(10)),NULL,NULL,NULL,0,'published','2026-06-26T19:24:18.398Z','2026-06-26T19:24:18.398Z',0,'Caraballeda','terremotovenezuela.com','2527a72e-9996-43bf-bd4c-58defeeb37f6','https://terremotovenezuela.com/edificio/2527a72e-9996-43bf-bd4c-58defeeb37f6','2026-06-26T18:05:38.072+00:00');
INSERT INTO "reports" ("id","building_name","address","state","latitude","longitude","damage_type","description","contact_name","contact_phone","contact_email","contact_consent","status","created_at","updated_at","needs_help","city","source_name","source_id","source_url","source_updated_at") VALUES('fe6508a4-230f-4e73-8680-efe3cf38c82f','Ciudad caribia','Cd Caribia, La Guaira, Venezuela','La Guaira',10.5347435,-67.0304633,'collapse','Departamentos afectado en toda ciudad caribia',NULL,NULL,NULL,0,'published','2026-06-26T19:24:36.552Z','2026-06-26T19:24:36.552Z',0,'Ciudad Caribia','terremotovenezuela.com','e4801c88-e486-454d-b1c9-7c74861840b6','https://terremotovenezuela.com/edificio/e4801c88-e486-454d-b1c9-7c74861840b6','2026-06-26T18:05:37.866+00:00');
INSERT INTO "reports" ("id","building_name","address","state","latitude","longitude","damage_type","description","contact_name","contact_phone","contact_email","contact_consent","status","created_at","updated_at","needs_help","city","source_name","source_id","source_url","source_updated_at") VALUES('92acbacc-7187-40d8-8676-c6811306b785','Edificio Centro Profesional Oeste','F3VF+HC4, Cjón. Machado, Caracas 1020, Distrito Capital, Venezuela','Distrito Capital',10.4938852,-66.9264191,'severe',replace('Reporte Tecnico de Daños Sismicos\nEl registro fotografico revela una degradacion estructural y arquitectonica severa en el inmueble por esfuerzos dinamicos horizontales que superaron el limite elastico.\n1 Envolvente Exterior\nLa fachada presenta una macrogrieta por corte diagonal desde la base del muro. Esta discontinuidad expone concentracion de tensiones en las esquinas, sugiriendo un desplazamiento diferencial entre el portico estructural y las paredes de cerramiento.\n2 Espacios Internos y Areas Comunes\nSe observa una condicion critica de fallas por traccion y corte diagonal.\nGrietas de separacion. Fracturas de gran apertura atraviesan las paredes interiores, comprometiendo la estabilidad del plano vertical en rutas de evacuacion y marcos de puertas.\nDescascaramiento mecanico. Desprendimiento de revestimiento y fragmentos de mamposteria en uniones pared techo y esquinas por el aplastamiento debido a la flexion del edificio.\nFisuramiento en puntos de rigidez. Fisuras secundarias junto a fosos de ascensores y luces de emergencia debido a la disipacion de la energia sismica en zonas no estructurales.\n3 Indicadores de Inestabilidad\nLa acumulacion de escombros y restos de concreto en oficinas y escaleras confirma que el agrietamiento es activo y reciente. Esto genera desestabilizacion y peligro de colapso de tabiques ante replicas.\nConclusion. El inmueble presenta daño no estructural severo con riesgo para la vida. Al perderse el confinamiento de la mamposteria, es obligatorio restringir el acceso de inmediato y realizar un escaneo estructural en los nodos principales.\n— Detalles en la fachada, paredes caídas. Amplias grietas, puertas descuadradas\n— Hundimiento leve del edificio, grietas en todas las paredes de la escaleras, bloques expuestos de un lado, entrada de apto descuadrada\n— Grietas, rupturas en la fachada','\n',char(10)),NULL,NULL,NULL,0,'published','2026-06-26T19:24:52.419Z','2026-06-26T19:24:52.419Z',0,'Caracas','terremotovenezuela.com','3c4dab2f-91df-445f-b656-906987f2ccde','https://terremotovenezuela.com/edificio/3c4dab2f-91df-445f-b656-906987f2ccde','2026-06-26T18:05:37.466+00:00');
