INSERT INTO "reports" ("id","building_name","address","state","latitude","longitude","damage_type","description","contact_name","contact_phone","contact_email","contact_consent","status","created_at","updated_at","needs_help","city","source_name","source_id","source_url","source_updated_at") VALUES('1a06cfe6-a5cd-4421-8577-e9e10fa5c29e','Jardín Los Ruices','Avenida Francisco de Miranda, Caracas, Distrito Capital, Venezuela','Distrito Capital',10.4907942810718,-66.8275832295754,'moderate',replace('Se cayeron paredes de varios pisos en la fachada. El edificio fue desalojado hasta evaluar los daños.\n— 25/06/2026 —\nEl Conjunto residencial Jardín Los Ruices consta de 2 torres con fachadas a la Av. Francisco de Miranda (Torre A) y Calle B (Torre B). Lo acá reportado corresponde solamente a la Torre A que fue la más afectada. Se evidencian por el momento solo daños en la mampostería en varios pisos de la fachada principal, especialmente en los apartamentos laterales colindantes con los edificios vecinos. No se reportan daños en ascensores, escaleras, pasillos internos y sótanos de estacionamiento. Los escombros caídos si afectaron los techos metálicos y vehículos ubicados en el nivel superior de estacionamiento que estaban al aire libre. No hubo heridos ni fallecidos. En horas del mediodía del día 25 de junio Defensa Civil hizo la inspección del edificio, y no se encontraron daños estructurales, solo terminaron de derrumbar algunas paredes inestables de pocos apartamentos.','\n',char(10)),NULL,NULL,NULL,0,'published','2026-06-26T20:10:24.458Z','2026-06-26T20:10:24.458Z',0,'Caracas','terremotovenezuela.com','b35bbfb3-6d99-4365-abfa-ba6bd4602c86','https://terremotovenezuela.com/edificio/b35bbfb3-6d99-4365-abfa-ba6bd4602c86','2026-06-26T15:24:40.509982+00:00');
